<?php
declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/portal_estudiante_layout.php';$portal=portalEstudianteCabecera('Avisos administrativos','avisos','Consulta solicitudes de correccion y avisos relacionados con tu cuenta.');$pdo=obtenerConexion();$q=$pdo->prepare('SELECT id,type,title,message,target_section,priority,status,due_at,read_at,resolved_at,created_at FROM admin_notices WHERE user_id=:id AND status<>\'cancelado\' ORDER BY FIELD(status,\'pendiente\',\'visto\',\'resuelto\'),created_at DESC');$q->execute(['id'=>(int)$portal['perfil']['id']]);$avisos=$q->fetchAll();?>
<div class="row"><div class="col-12"><div class="card"><div class="card-header"><h1 class="card-title mb-1">Avisos administrativos</h1><p class="text-muted mb-0">El contenido se muestra como texto seguro; no se interpreta HTML enviado por terceros.</p></div><div class="card-body"><?php foreach($avisos as $aviso):?><article class="border rounded p-3 mb-3"><div class="d-flex flex-wrap justify-content-between gap-2"><div><span class="badge <?= $aviso['priority']==='urgente'?'bg-danger':($aviso['priority']==='alta'?'bg-warning':'bg-primary') ?>"><?= atenea_e(ucfirst((string)$aviso['priority'])) ?></span><h2 class="h5 mt-2 mb-1"><?= atenea_e((string)$aviso['title']) ?></h2></div><span><?= atenea_e(ucfirst((string)$aviso['status'])) ?></span></div><p><?= nl2br(atenea_e((string)$aviso['message'])) ?></p><?php if($aviso['target_section']):?><p><strong>Seccion:</strong> <?= atenea_e((string)$aviso['target_section']) ?></p><?php endif;?><?php if($aviso['due_at']):?><p><strong>Fecha limite:</strong> <?= date('d/m/Y',strtotime((string)$aviso['due_at'])) ?></p><?php endif;?><small class="text-muted">Creado el <?= date('d/m/Y H:i',strtotime((string)$aviso['created_at'])) ?></small><?php if(in_array($aviso['status'],['pendiente','visto'],true)):?><form class="mt-3" method="post" action="<?= atenea_url('src/estudiantes/aviso-accion.php') ?>"><input type="hidden" name="csrf_token" value="<?= atenea_e(obtenerTokenCsrf()) ?>"><input type="hidden" name="id" value="<?= (int)$aviso['id'] ?>"><?php if($aviso['status']==='pendiente'):?><button class="btn btn-outline-primary" name="accion" value="visto">Marcar como visto</button><?php endif;?> <button class="btn btn-success" name="accion" value="resuelto">Marcar como resuelto</button></form><?php endif;?></article><?php endforeach;?><?php if(!$avisos):?><div class="text-center py-5 text-muted"><i class="bi bi-bell-slash display-4"></i><p class="mt-3">No tienes avisos administrativos.</p></div><?php endif;?></div></div></div></div><?php portalEstudiantePie(); ?>
